const translated = $json.translated;
let cart = [...$json.cart];
const idx = parseInt(translated.replace('remove ', '')) - 1;

let reply = '';

if (isNaN(idx) || idx < 0 || idx >= cart.length) {
  reply = 'I couldn't find that item in your cart.

To adjust quantity:
1. Type *remove [exact product name]* to remove it
2. Then type *buy [product name]* to add it back

Type *cart* to view your current cart.
Type *menu* to return to main menu.';
} else {
  const removed = cart.splice(idx, 1)[0];
  const cartSummary = cart.length > 0
    ? 'Your Cart:

' + cart.map((c, i) => `${i+1}. *${c.name}* x${c.qty} — PKR ${c.price * c.qty}`).join('
') + '

Total: PKR ' + cart.reduce((s, c) => s + c.price * c.qty, 0)
    : 'Your cart is empty.';
  reply = `Removed *${removed.name}* from cart.

${cartSummary}

Type *checkout* to order.
Type *menu* to return to main menu.`;
}

return [{json: {...$json, reply, cart}}];

const cart = $json.cart;
let reply = '';
let orderState = null;

if (cart.length === 0) {
  reply = 'Your cart is empty! Add products first.\n\nType *1* to browse products.\nType *buy [product name]* to add to cart.';
} else {
  const cartSummary = cart.map((c, i) => `${i+1}. *${c.name}* x${c.qty} — PKR ${c.price * c.qty}`).join('\n');
  const total = cart.reduce((s, c) => s + c.price * c.qty, 0);
  reply = `Your Cart:\n\n${cartSummary}\n\nTotal: PKR ${total}\n\nLet's complete your order!\n\nPlease enter your full name:\n(Type *menu* to cancel)`;
  orderState = 'collecting_name';
}

return [{json: {...$json, reply, orderState: orderState || $json.orderState, orderData: {}}}];

const translated = $json.translated;
const products = $json.products;
let cart = [...$json.cart];
let lastProduct = $json.lastProduct;

// Strip filler words to find product hint
const noise = ['yes','yeah','yep','sure','ok','i','want','to','buy','wanna','now','please','order','purchase','the','a','an','it','this','that','get','me','can','will','would','like','let','do','some','one','more','add'];
const hint = translated.split(' ').filter(w => w.length > 1 && !noise.includes(w)).join(' ').trim();

let target = null;
let reply = '';

if (hint.length > 2) {
  // Exact match
  target = products.find(p => p.product_name && p.product_name.toLowerCase() === hint);

  if (!target) {
    // Strong match — all words in name
    const words = hint.split(' ').filter(w => w.length > 2);
    const strong = products.filter(p => {
      const name = (p.product_name || '').toLowerCase();
      return words.length > 0 && words.every(w => name.includes(w));
    });

    if (strong.length === 1) {
      target = strong[0];
    } else if (strong.length > 1) {
      const list = strong.slice(0, 8).map((p, i) => `${i+1}. *${p.product_name}*\n   PKR ${p.price} | ${p.stock}\n   ${p.product_url}`).join('\n\n');
      reply = `Found *${strong.length} products* matching "${hint}":\n\n${list}\n\nType *buy [exact product name]* to add to cart.\nType *menu* to return to main menu.`;
      return [{json: {...$json, reply, cart, lastProduct: strong[0]}}];
    } else {
      // Broad match
      const broad = products.filter(p => {
        const text = [p.product_name||'',p.category||'',p.keywords||'',p.description||''].join(' ').toLowerCase();
        return words.every(w => text.includes(w));
      });
      if (broad.length === 1) target = broad[0];
      else if (broad.length > 1) {
        const list = broad.slice(0, 8).map((p, i) => `${i+1}. *${p.product_name}*\n   PKR ${p.price} | ${p.stock}\n   ${p.product_url}`).join('\n\n');
        reply = `Found *${broad.length} products* matching "${hint}":\n\n${list}\n\nType *buy [exact product name]* to add to cart.\nType *menu* to return to main menu.`;
        return [{json: {...$json, reply, cart, lastProduct: broad[0]}}];
      }
    }
  }
}

// If no product in message, use last viewed
if (!target && lastProduct) target = lastProduct;

if (!target) {
  reply = 'Please tell me which product you want!\n\nType *catalogue* to keep browsing.\nType *menu* to return to main menu.';
  return [{json: {...$json, reply, cart}}];
}

// Stock check
const stock = (target.stock || '').toLowerCase();
const inStock = stock.includes('in stock') || stock.includes('available') || stock.includes('yes');
if (!inStock) {
  reply = `Sorry, *${target.product_name}* is currently out of stock.\n\nFor restock updates:\n📞 WhatsApp: +923010756404\n\nType *catalogue* to browse available products.\nType *menu* to return to main menu.`;
  return [{json: {...$json, reply, cart}}];
}

// Add to cart
const existing = cart.find(c => c.name === target.product_name);
if (existing) { existing.qty += 1; } else { cart.push({name: target.product_name, price: target.price, qty: 1}); }

const total = cart.reduce((s, c) => s + c.price * c.qty, 0);
const cartLines = cart.map((c, i) => `${i+1}. *${c.name}* x${c.qty} — PKR ${c.price * c.qty}`).join('\n');

reply = `Added *${target.product_name}* (PKR ${target.price}) to cart!\n\nYour Cart (${cart.length} items):\n\n${cartLines}\n\nTotal: PKR ${total}\n\nType *catalogue* to keep browsing.\nType *checkout* when you're ready.\nType *menu* to return to main menu.`;

return [{json: {...$json, reply, cart, lastProduct: target}}];

const message = $json.message;
const lowerMsg = $json.lowerMsg;
const translated = $json.translated || lowerMsg || message;
let orderState = $json.orderState;
let orderData = {...$json.orderData};
let cart = typeof $json.cart === 'string' ? JSON.parse($json.cart || '[]') : (Array.isArray($json.cart) ? $json.cart : []);
const company = $json.company;
let reply = '';

// Escape detection — let user break out of order flow
const lowerCheck = (lowerMsg || message || '').toLowerCase();
const escapeWords = ['menu', 'cancel', 'back', 'remove', 'cart', 'clear', 'wapis', 'nahi', 'stop'];
if (escapeWords.some(w => lowerCheck.includes(w)) || lowerCheck.includes('only want') || lowerCheck.includes('change') || lowerCheck.includes('dont want') || lowerCheck.includes("don't want") || lowerCheck.includes('not three') || lowerCheck.includes('not two') || lowerCheck.includes('wrong')) {
  return [{json: {...$json, reply: 'Order paused. Your cart is still saved.\n\nType *cart* to view/edit your cart.\nType *remove [product name]* to remove items.\nType *checkout* to restart checkout.\nType *menu* to return to main menu.', orderState: null, orderData: {}}}];
}

// Validation helpers
function validateName(n) {
  const t = n.trim();
  if (t.length < 3) return {valid: false, msg: 'Name is too short. Please enter your full name (first and last):'};
  if (/^\d+$/.test(t)) return {valid: false, msg: 'That looks like a number. Please enter your full name:'};
  if (/[!@#$%^&*()_+=\[\]{}|\\:";\'<>?,./]/.test(t)) return {valid: false, msg: 'Please enter your name without special characters:'};
  return {valid: true};
}
function validatePhone(ph) {
  const c = ph.replace(/[\s\-\(\)]/g, '');
  if (/^03\d{9}$/.test(c)) return {valid: true, formatted: c};
  if (/^\+923\d{9}$/.test(c)) return {valid: true, formatted: c};
  if (/^923\d{9}$/.test(c)) return {valid: true, formatted: '+' + c};
  return {valid: false};
}
function validateAddress(a) {
  if (a.trim().length < 10) return {valid: false, msg: 'Address is too short. Please include city, area, and street.\nExample: Lahore, DHA Phase 5, Street 12, House 45'};
  return {valid: true};
}

// ── COLLECTING NAME ──
if (orderState === 'collecting_name') {
  const check = validateName(message);
  if (!check.valid) {
    reply = `${check.msg}\n(Type *menu* to cancel order)`;
    return [{json: {...$json, reply, orderState, orderData, cart}}];
  }
  orderData.name = message.trim();
  orderState = 'collecting_phone';
  reply = `Got it ${orderData.name}!\n\nPlease share your WhatsApp number:\n(Format: 03XX-XXXXXXX)\n(Type *menu* to cancel order)`;
}
// ── COLLECTING PHONE ──
else if (orderState === 'collecting_phone') {
  const check = validatePhone(message);
  if (!check.valid) {
    reply = `That doesn't look like a valid Pakistani phone number.\n\nPlease enter in format: 03XX-XXXXXXX\nExample: 03001234567\n(Type *menu* to cancel order)`;
    return [{json: {...$json, reply, orderState, orderData, cart}}];
  }
  orderData.phone = check.formatted;
  orderState = 'collecting_address';
  reply = `Phone saved: ${check.formatted}\n\nPlease share your delivery address:\n(Include city, area, street — be specific for delivery)\nExample: Lahore, DHA Phase 5, Street 12, House 45\n(Type *menu* to cancel order)`;
}
// ── COLLECTING ADDRESS ──
else if (orderState === 'collecting_address') {
  const check = validateAddress(message);
  if (!check.valid) {
    reply = `${check.msg}\n(Type *menu* to cancel order)`;
    return [{json: {...$json, reply, orderState, orderData, cart}}];
  }
  orderData.address = message.trim();
  orderState = 'collecting_payment';
  reply = `Address saved!\n\nChoose payment method:\n\n1 - Cash on Delivery (COD)\n2 - Online Payment (Bank Transfer)\n(Type *menu* to cancel order)`;
}
// ── COLLECTING PAYMENT ──
else if (orderState === 'collecting_payment') {
  if (lowerMsg === '1' || lowerMsg.includes('cod') || lowerMsg.includes('cash')) {
    orderData.payment = 'Cash on Delivery';
  } else if (lowerMsg === '2' || lowerMsg.includes('online') || lowerMsg.includes('bank')) {
    orderData.payment = 'Online Payment';
  } else {
    reply = 'Please type *1* for Cash on Delivery or *2* for Online Payment:\n(Type *menu* to cancel order)';
    return [{json: {...$json, reply, orderState, orderData, cart}}];
  }
  // Show confirmation
  orderState = 'confirming_order';
  const cartLines = cart.map((c, i) => `${i+1}. ${c.name} x${c.qty} — PKR ${c.price * c.qty}`).join('\n');
  const total = cart.reduce((s, c) => s + c.price * c.qty, 0);
  reply = `Please review your order:\n\n${cartLines}\n\nTotal: PKR ${total}\nName: ${orderData.name}\nPhone: ${orderData.phone}\nAddress: ${orderData.address}\nPayment: ${orderData.payment}\n\nType *confirm* to place this order.\nType *menu* to cancel.`;
}

return [{json: {...$json, reply, orderState, orderData, cart}}];

const translated = $json.translated || $json.lowerMsg || $json.message;
let orderState = $json.orderState;
let orderData = {...$json.orderData};
let cart = [...$json.cart];
const company = $json.company;
let reply = '';
let orderComplete = false;
let orderRecord = null;
let customerRecord = null;

const yesWords = ['confirm','yes','haan','han','ji','jee','bilkul','theek','thik','ok','sahi','y'];

if (yesWords.some(w => translated === w || translated.includes(w))) {
  // Place order
  const orderId = 'WM-' + Date.now().toString().slice(-6);
  const items = cart.map(c => `${c.name} x${c.qty}`).join(', ');
  const total = cart.reduce((s, c) => s + c.price * c.qty, 0);

  const paymentNote = orderData.payment === 'Online Payment'
    ? `\n\nBank Details:\nBank: ${company.bank_name}\nAccount No: ${company.bank_account}\nIBAN: ${company.bank_iban}\nTitle: ${company.bank_title}\n\nSend screenshot on WhatsApp to confirm.`
    : '';

  reply = `Order Placed!\n\nOrder ID: *${orderId}*\nProducts: ${items}\nTotal: PKR ${total}\nName: ${orderData.name}\nPhone: ${orderData.phone}\nAddress: ${orderData.address}\nPayment: ${orderData.payment}${paymentNote}\n\nWe'll contact you within 24 hours!\nThank you for choosing WaltonMarket!\n\nType *menu* to continue shopping.`;

  orderRecord = {
    order_id: orderId,
    session_id: $json.sessionId,
    customer_name: orderData.name,
    phone: orderData.phone,
    address: orderData.address,
    products: items,
    total_price: total,
    payment_method: orderData.payment,
    status: 'Pending'
  };

  orderComplete = true; 
  // Build customer record for saving
  const customerRecord = {
    phone: orderData.phone,
    name: orderData.name,
    address: orderData.address
  };
  orderState = null;
  orderData = {};
  cart = [];
} else {
  // Cancel
  orderState = null;
  orderData = {};
  const cartSummary = cart.length > 0
    ? 'Your cart is still saved.\n\n' + cart.map((c, i) => `${i+1}. *${c.name}* x${c.qty} — PKR ${c.price * c.qty}`).join('\n')
    : '';
  reply = `Order cancelled. ${cartSummary}\n\nType *checkout* to try again.\nType *menu* to return to main menu.`;
}

return [{json: {...$json, reply, orderState, orderData, cart, orderComplete, orderRecord, customerRecord}}];

if (!$json.sessionId && !$json.reply) return [];

const sessionId = $json.sessionId || $('Build AI Prompt').first().json.sessionId;
const bap = $('Build AI Prompt').first().json;

const existingHistory = Array.isArray($json.history) ? $json.history : (Array.isArray(bap.history) ? bap.history : []);
const updatedHistory = [...existingHistory];
updatedHistory.push({role: 'user', text: $json.message || bap.message, ts: Date.now()});
updatedHistory.push({role: 'assistant', text: $json.reply, ts: Date.now()});
const trimmedHistory = updatedHistory.slice(-20);

const esc = (v) => typeof v === 'string' ? v.replace(/'/g, "''") : JSON.stringify(v || null).replace(/'/g, "''");
const orderState = $json.orderState !== undefined ? $json.orderState : (bap.orderState || null);

const sqlQuery = `INSERT INTO sessions (session_id, history, order_state, order_data, last_product, cart, current_page)
VALUES (
  '${esc(sessionId)}',
  '${esc(trimmedHistory)}'::jsonb,
  ${orderState ? "'" + esc(orderState) + "'" : 'NULL'},
  '${esc($json.orderData || bap.orderData || {})}'::jsonb,
  '${esc($json.lastProduct || bap.lastProduct || null)}'::jsonb,
  '${esc(Array.isArray($json.cart) ? $json.cart : (Array.isArray(bap.cart) ? bap.cart : []))}'::jsonb,
  ${$json.currentPage || bap.currentPage || 0}
)
ON CONFLICT (session_id) DO UPDATE SET
  history = EXCLUDED.history,
  order_state = EXCLUDED.order_state,
  order_data = EXCLUDED.order_data,
  last_product = EXCLUDED.last_product,
  cart = EXCLUDED.cart,
  current_page = EXCLUDED.current_page`;

return [{json: {
  sqlQuery,
  reply: $json.reply,
  orderComplete: $json.orderComplete || false,
  orderRecord: $json.orderRecord || null,
  customerPhone: $json.orderComplete ? ($json.orderRecord?.phone || null) : null,
  customerName: $json.orderComplete ? ($json.orderRecord?.customer_name || null) : null,
  customerAddress: $json.orderComplete ? ($json.orderRecord?.address || null) : null
}}];
