// ============ ESCALATION CHECK (30-min cooldown) ============
const escalatedAt = session?.escalated_at ? new Date(session.escalated_at) : null;
if (escalatedAt) {
  const minutesSinceEscalation = (Date.now() - escalatedAt.getTime()) / 60000;
  if (minutesSinceEscalation < 30) {
    // Allow "menu" to bypass escalation
    if (lowerMsg === 'menu') {
      return [{json: {
