  if (negativeFeedback) {
    returningCustomerInfo += ` | WARNING: Previous negative feedback on ${negativeFeedback.quote_ref}`;
  }
}

// ============ CONVERSATION HISTORY ============
const recentHistory = Array.isArray(history) ? history.slice(-2).map(h => `${h.role}: ${h.text}`).join('\n') : '';

// ============ ACTIVE FLOW SKIPS ============
if (orderState && (orderState.startsWith('collecting_') || orderState === 'confirming_order')) {
