    newQuoteState: 'collecting_customer_info',
    newQuoteData: {},
    sessionId,
    proceedToCalculator: false
  }}];
}

// STATE 1: collecting_customer_info -> parse name/phone/address
if (quoteState === 'collecting_customer_info') {

  if (/^(menu|cancel|wapas|back)$/i.test(message.trim())) {
    return [{json: {
      action: 'reply_and_save',
      reply: 'Quotation cancelled. Type *menu* to return to main menu.',
      newQuoteState: null,
      newQuoteData: {},
      sessionId,
      proceedToCalculator: false
    }}];
  }

  // Phone extraction — find phone number anywhere in message
  const phoneRegex = /(0\d{9,10}|\+92\d{10}|92\d{10})/;
  const phoneStructured = message.match(/phone\s*[:\-]\s*([0-9+\s]{10,14})/i);
  const phoneInline = message.match(phoneRegex);
  const rawPhone = phoneStructured?.[1]?.trim() || phoneInline?.[0] || null;

  // Name extraction — everything BEFORE the phone number on same line
  const nameLabeled = message.match(/name\s*[:\-]\s*(.+?)(?:\n|$)/i);
  let name = nameLabeled?.[1]?.trim() || null;

  if (!name && rawPhone) {
    // Find where phone appears and take text before it as name
    const beforePhone = message.substring(0, message.indexOf(rawPhone)).trim();
    // Clean up: take last line before phone
    const beforeLines = beforePhone.split('\n').map(l => l.trim()).filter(Boolean);
    if (beforeLines.length > 0) {
      // Last non-empty line before phone = name
      name = beforeLines[beforeLines.length - 1].trim();
    }
  }

  if (!name) {
    // Fallback: first line that isn't a phone number
    const lines = message.split('\n').map(l => l.trim()).filter(Boolean);
    for (const line of lines) {
      if (!phoneRegex.test(line) && line.length > 1) {
        name = line;
        break;
      }
    }
  }

  // Address extraction — everything AFTER the phone number
  const addressLabeled = message.match(/address\s*[:\-]\s*(.+?)(?:\n|$)/i);
  let address = addressLabeled?.[1]?.trim() || '';

  if (!address && rawPhone) {
    const phoneIdx = message.indexOf(rawPhone);
    if (phoneIdx !== -1) {
      const afterPhone = message.substring(phoneIdx + rawPhone.length).trim();
      // Remove leading punctuation/newlines
      address = afterPhone.replace(/^[,\s\n]+/, '').split('\n')[0].trim();
    }
  }

  if (!name || !rawPhone) {
    return [{json: {
      action: 'reply_and_save',
      reply: '❌ Naam aur phone number zaroor chahiye. Aise bhejein:\n\nAhmad Ali\n03001234567\nLahore, DHA\n\n_Type *menu* to cancel._',
      newQuoteState: 'collecting_customer_info',
      newQuoteData: quoteData,
      sessionId,
      proceedToCalculator: false
    }}];
  }

  const updatedQuoteData = {
    customerName: name,
    customerPhone: rawPhone,
    customerAddress: address
  };

  return [{json: {
    action: 'reply_and_save',
    reply: '✅ Shukriya, ' + name + '!\n\nAb apne ghar ki details share karein:\n\n1️⃣ Sheher & area\n2️⃣ Ghar ka size (marlas) & manzilain (stories/floors)\n3️⃣ Poora ghar automate karna hai ya sirf kuch areas?\n4️⃣ Rooms ki tadaad: Bedrooms | Bathrooms | Kitchen | Living Room | Drawing Room | Garage\n5️⃣ Andaza: Lights | Fans | Switches\n6️⃣ Kya chahiye? (yes/no): Smart Curtains | Smart Door Locks | Human Presence Sensors\n7️⃣ Smart Touch Panels: no | 4-gang (PKR 14,500) | alexa (PKR 32,500)\n8️⃣ Ghar zair-e-taameer hai? (wiring chahiye?)\n\nSaari details ek message mein bhejein! 🏡',
    newQuoteState: 'collecting_house_details',
    newQuoteData: updatedQuoteData,
    sessionId,
    proceedToCalculator: false
  }}];
}

// STATE 2: collecting_house_details -> parse & pass to calculator
if (quoteState === 'collecting_house_details') {

  if (/^(menu|cancel|wapas|back)$/i.test(message.trim())) {
    return [{json: {
      action: 'reply_and_save',
      reply: 'Quotation cancelled. Type *menu* to return to main menu.',
      newQuoteState: null,
      newQuoteData: {},
      sessionId,
      proceedToCalculator: false
    }}];
  }

  const msg = message;

  // City
  const cityPatterns = [
    /(?:^|\n)\s*1\s*[:\.\-]\s*([A-Za-z\s]{3,40}?)(?:\n|,|$)/m,
    /(lahore|karachi|islamabad|rawalpindi|faisalabad|multan|okara|sahiwal|gujranwala|sialkot|peshawar|quetta)/i
  ];
  let city = 'Not specified';
  for (const p of cityPatterns) {
    const m = msg.match(p);
    if (m) { city = m[1].trim(); break; }
  }

  // Size
  const marlaMatch = msg.match(/(\d+)\s*marla/i);
  const marlas = marlaMatch ? parseInt(marlaMatch[1]) : 0;
  const stories = msg.match(/double\s*stor/i) ? 2
    : msg.match(/triple\s*stor/i) ? 3
    : msg.match(/(\d+)\s*stor(?:y|ies|ey)/i) ? parseInt(msg.match(/(\d+)\s*stor/i)[1])
    : msg.match(/(\d+)\s*manzil/i) ? parseInt(msg.match(/(\d+)\s*manzil/i)[1])
    : 1;

  // Rooms
  const num = (regex) => { const m = msg.match(regex); return m ? parseInt(m[1]) : 0; };
  const rooms = {
    bedrooms:     num(/(\d+)\s*bed(?:room)?/i),
    bathrooms:    num(/(\d+)\s*bath(?:room)?/i),
    kitchens:     num(/(\d+)\s*kitchen/i),
    livingRooms:  num(/(\d+)\s*living/i),
    drawingRooms: num(/(\d+)\s*drawing/i),
    garages:      num(/(\d+)\s*garage/i)
  };

  // Devices
  const lights   = num(/(\d+)\+?\s*light/i);
  const fans     = num(/(\d+)\+?\s*fan/i);
  const switches = num(/(\d+)\+?\s*switch(?:es|board)?/i);

  // Extras (negation-aware)
  const wantsExtra = (keyword) => {
    const negated = new RegExp('(?:no|nahi|nay|don\'t|dont)[^\\n]{0,20}' + keyword + '|' + keyword + '[^\\n]{0,20}(?:nahi|no)', 'i');
    const positive = new RegExp(keyword, 'i');
    return positive.test(msg) && !negated.test(msg);
  };

  const extras = {
    smartCurtains:   wantsExtra('curtain'),
    smartLocks:      wantsExtra('(?:door\\s*)?lock'),
    presenceSensors: wantsExtra('presence\\s*sensor'),
    wiring:          /under\s*construct|zair.e.taameer|wiring.*yes|yes.*wiring/i.test(msg)
  };

  // Touch panel type detection
  // Check for alexa version first, then 4-gang, then no
  let touchPanelType = 'none';
  if (/alexa/i.test(msg)) {
    touchPanelType = 'alexa';
  } else if (/4.gang|4gang|touch panel.*yes|yes.*touch panel|touch.*panel/i.test(msg) && !/no.*touch|touch.*no/i.test(msg)) {
    touchPanelType = '4gang';
  } else if (/touch/i.test(msg) && !/no.*touch|touch.*no/i.test(msg)) {
    touchPanelType = '4gang'; // default to cheaper if just "touch" mentioned
  }

  const mainRooms = rooms.bedrooms + rooms.livingRooms + rooms.drawingRooms;
  const extraCounts = {
    curtains:        extras.smartCurtains   ? Math.max(mainRooms * 2, 2) : 0,
    locks:           extras.smartLocks      ? 2 : 0,
    touchPanels:     touchPanelType !== 'none' ? Math.max(Math.ceil(mainRooms / 2), 1) : 0,
    presenceSensors: extras.presenceSensors ? Math.max(mainRooms, 1) : 0,
    touchPanelType
  };

  const finalQuoteData = {
    ...quoteData,
    city, marlas, stories,
    rooms, devices: { lights, fans, switches },
    extras, extraCounts,
    rawMessage: msg
  };

  return [{json: {
    action: 'proceed_to_calculator',
    reply: null,
    newQuoteState: null,
    newQuoteData: {},
    sessionId,
    proceedToCalculator: true,
    quoteData: finalQuoteData
  }}];
}

