}

// DRAWING ROOMS: 4-gang switch + standalone fan + lights
const drawingRooms = rooms.drawingRooms || 0;
if (drawingRooms > 0) {
  addItem('switch_4gang_drawing', P.switch_4gang, drawingRooms, 'Drawing Room: 4-Gang Switch Board');
  addItem('fan_standalone', P.fan_standalone, drawingRooms, 'Drawing Room: Fan Switch');
  if (lightsPerRoom > 0) addItem('bulb_rgb', P.bulb_rgb, drawingRooms * lightsPerRoom, 'Drawing Room: Smart Bulbs');
}

// KITCHENS: 2-gang switch + 1 wall socket + lights
const kitchens = rooms.kitchens || 0;
if (kitchens > 0) {
  addItem('switch_2gang_kitchen', P.switch_2gang, kitchens, 'Kitchen: 2-Gang Switch Board');
  addItem('wall_socket', P.wall_socket, kitchens, 'Kitchen: Wall Socket');
  if (lightsPerRoom > 0) addItem('bulb_rgb', P.bulb_rgb, kitchens * lightsPerRoom, 'Kitchen: Smart Bulbs');
}

// BATHROOMS: 2-gang switch + lights
const bathrooms = rooms.bathrooms || 0;
if (bathrooms > 0) {
  addItem('switch_2gang_bath', P.switch_2gang, bathrooms, 'Bathroom: 2-Gang Switch Board');
  if (lightsPerRoom > 0) addItem('bulb_rgb', P.bulb_rgb, bathrooms * lightsPerRoom, 'Bathroom: Smart Bulbs');
}

// GARAGES: 2-gang switch
const garages = rooms.garages || 0;
if (garages > 0) {
  addItem('switch_2gang_garage', P.switch_2gang, garages, 'Garage: 2-Gang Switch Board');
}

// ─────────────────────────────────────────────
// EXTRAS
// ─────────────────────────────────────────────
if (extraCounts.curtains > 0) {
  addItem('curtain_motor', P.curtain_motor, extraCounts.curtains, 'Smart Curtains');
}
if (extraCounts.locks > 0) {
  addItem('smart_lock', P.smart_lock, extraCounts.locks, 'Smart Door Locks');
}
if (extraCounts.touchPanels > 0) {
  const panelPricing = (extraCounts.touchPanelType === 'alexa') ? P.touch_panel_alexa : P.touch_panel_4g;
  addItem('touch_panel', panelPricing, extraCounts.touchPanels, 'Smart Touch Panels');
}
if (extraCounts.presenceSensors > 0) {
  addItem('presence_sensor', P.presence_sensor, extraCounts.presenceSensors, 'Human Presence Sensors');
}

// ─────────────────────────────────────────────
// BUILD FINAL ITEMS LIST + SUBTOTAL
// ─────────────────────────────────────────────
const items = [];
let subtotal = 0;

for (const key of Object.keys(itemMap)) {
  const { pricing, qty, category } = itemMap[key];
  const unitTotal = pricing.product + pricing.install;
  const lineTotal = qty * unitTotal;
  items.push({
    name: pricing.name,
    category,
    qty,
    productPrice: pricing.product,
    installPrice: pricing.install,
    unitTotal,
    lineTotal,
    note: pricing.note || null
  });
  subtotal += lineTotal;
}

// ─────────────────────────────────────────────
// DISCOUNT TIERS
// ─────────────────────────────────────────────
let discountRate = 0;
let discountLabel = '';
if (subtotal > 200000) {
  discountRate = 0.15;
  discountLabel = '15% Discount (Order above PKR 200,000)';
} else if (subtotal > 100000) {
  discountRate = 0.10;
  discountLabel = '10% Discount (Order above PKR 100,000)';
}

const discountAmount = Math.round(subtotal * discountRate);
const grandTotal = subtotal - discountAmount;

// ─────────────────────────────────────────────
// FORMATTING
// ─────────────────────────────────────────────
const fmt = (n) => n.toLocaleString('en-US');
const quoteRef = 'WM-' + Date.now().toString().slice(-6);
