text += '👤 *Customer:* ' + customerName + '\n';
text += '📱 *Phone:* ' + customerPhone + '\n';
if (customerAddress) text += '📍 *Address:* ' + customerAddress + '\n';
text += '🏡 *Property:* ' + (marlas > 0 ? marlas + ' Marla' : '') + (stories > 1 ? ', ' + stories + ' Stories' : ', 1 Story') + ' — ' + city + '\n';

// Room summary
const roomParts = [];
if (bedrooms > 0) roomParts.push(bedrooms + ' Bedroom' + (bedrooms > 1 ? 's' : ''));
if (bathrooms > 0) roomParts.push(bathrooms + ' Bathroom' + (bathrooms > 1 ? 's' : ''));
if (kitchens > 0) roomParts.push(kitchens + ' Kitchen' + (kitchens > 1 ? 's' : ''));
if (livingRooms > 0) roomParts.push(livingRooms + ' Living Room' + (livingRooms > 1 ? 's' : ''));
if (drawingRooms > 0) roomParts.push(drawingRooms + ' Drawing Room' + (drawingRooms > 1 ? 's' : ''));
if (garages > 0) roomParts.push(garages + ' Garage' + (garages > 1 ? 's' : ''));
if (roomParts.length > 0) text += '🚪 *Rooms:* ' + roomParts.join(' | ') + '\n';
text += '━━━━━━━━━━━━━━━━━━━━\n\n';

text += '*📦 QUOTATION BREAKDOWN*\n\n';

for (const item of items) {
  text += '▪️ *' + item.name + '*\n';
  if (item.note) text += '   _⚠️ ' + item.note + '_\n';
  text += '   Qty: ' + item.qty + ' × PKR ' + fmt(item.unitTotal) + '\n';
  text += '   _(Product: PKR ' + fmt(item.productPrice) + ' + Install: PKR ' + fmt(item.installPrice) + ')_\n';
  text += '   = *PKR ' + fmt(item.lineTotal) + '*\n\n';
}

text += '━━━━━━━━━━━━━━━━━━━━\n';
text += 'Subtotal: PKR ' + fmt(subtotal) + '\n';
if (discountRate > 0) {
  text += '🎉 *' + discountLabel + '*\n';
  text += 'Discount: -PKR ' + fmt(discountAmount) + '\n';
}
text += '\n💰 *GRAND TOTAL: PKR ' + fmt(grandTotal) + '*\n';
text += '━━━━━━━━━━━━━━━━━━━━\n\n';
text += '⚠️ _System-generated estimate. Final pricing may vary based on actual site requirements._\n';
