text += '🗺️ https://maps.app.goo.gl/uSmAJPZrEqJbN7Yh6\n\n';
text += '_Type *menu* to return to main menu._';

// ─────────────────────────────────────────────
// OUTPUT
// ─────────────────────────────────────────────
return [{json: {
