// QUOTE FEEDBACK HANDLER
// Handles two states:
// quote_feedback_pending -> waiting for yes/no
// quote_feedback_detail  -> waiting for "what was wrong"

const buildData = $('Build AI Prompt').first().json;
const message = buildData.message.trim();
const sessionId = buildData.sessionId;
const session = buildData.session || {};

const quoteState = session.quote_state || null;
const quoteData = typeof session.quote_data === 'string'
  ? JSON.parse(session.quote_data)
  : (session.quote_data || {});

// ─────────────────────────────────────────────
// STATE: quote_feedback_pending
// Customer just received quotation — ask if helpful
// ─────────────────────────────────────────────
if (quoteState === 'quote_feedback_pending') {

  const isYes = /^(yes|haan|han|hnji|bilkul|helpful|good|great|theek|ok|okay|👍)/i.test(message);
  const isNo  = /^(no|nahi|nay|nope|not|galt|wrong|incorrect|👎)/i.test(message);

  if (isYes) {
    return [{json: {
      action: 'save_feedback',
      feedback: 'positive',
      feedbackComment: null,
      quoteRef: quoteData.quoteRef,
      customerPhone: quoteData.customerPhone,
      reply: '✅ Shukriya! Khushi hui ke quotation helpful thi.\n\nKoi bhi sawaal ho to hum hamesha yahan hain. 😊\n\nType *menu* to return to main menu.',
      newQuoteState: null,
      newQuoteData: {},
      sessionId,
      proceedToCalculator: false
    }}];
  }

  if (isNo) {
    return [{json: {
      action: 'ask_feedback_detail',
      feedback: 'negative',
      feedbackComment: null,
      quoteRef: quoteData.quoteRef,
      customerPhone: quoteData.customerPhone,
      reply: '😔 Afsos hua. Kya masla tha? Please batayein taake hum behtar kar sakein:\n\n- Pricing zyada thi?\n- Koi product missing tha?\n- Kuch samajh nahi aaya?\n- Kuch aur?\n\n_Apna jawab type karein._',
      newQuoteState: 'quote_feedback_detail',
      newQuoteData: quoteData,
      sessionId,
      proceedToCalculator: false
    }}];
  }

  // Unrecognized response — remind
  return [{json: {
    action: 'remind_feedback',
    feedback: null,
    feedbackComment: null,
    quoteRef: quoteData.quoteRef,
    customerPhone: quoteData.customerPhone,
    reply: 'Kya aapko quotation helpful lagi?\n\n✅ *Yes* — agar helpful thi\n❌ *No* — agar koi masla tha\n\n_Type *menu* to skip._',
    newQuoteState: 'quote_feedback_pending',
    newQuoteData: quoteData,
    sessionId,
    proceedToCalculator: false
  }}];
}

// ─────────────────────────────────────────────
// STATE: quote_feedback_detail
// Customer explaining what was wrong
// ─────────────────────────────────────────────
if (quoteState === 'quote_feedback_detail') {

  const comment = message;

  return [{json: {
    action: 'save_feedback',
    feedback: 'negative',
    feedbackComment: comment,
    quoteRef: quoteData.quoteRef,
    customerPhone: quoteData.customerPhone,
    reply: '✅ Shukriya feedback ke liye! Hum is par kaam karenge aur aapke liye behtar quotation banayenge.\n\nKisi bhi sawaal ke liye:\n📞 +923010756404\n\nType *menu* to return to main menu.',
    newQuoteState: null,
    newQuoteData: {},
    sessionId,
    proceedToCalculator: false
  }}];
}

// Fallback
return [{json: {
  action: 'skip',
  feedback: null,
  feedbackComment: null,
  quoteRef: null,
  customerPhone: null,
  reply: 'Type *menu* to return to main menu.',
  newQuoteState: null,
  newQuoteData: {},
  sessionId,
  proceedToCalculator: false
}}];

